sys_script.script:
/**
 * Before Update: Populates closed_at (Resolution Timestamp) when State changes to
 * Resolved (3), Closed Incomplete (4), or Closed Skipped (7).
 * Globals: current, previous, gs
 */
(function executeRule(current, previous) {
    var newState = current.getValue('state');
    var oldState = previous.getValue('state');

    // Only act if state actually changed
    if (newState == oldState) {
        return;
    }

    // Resolved or Closed states: 3 (Closed Complete), 4 (Closed Incomplete), 7 (Closed Skipped)
    if (newState == '3' || newState == '4' || newState == '7') {
        // Only set if not already set (avoid overwriting on re-close)
        if (!current.getValue('closed_at')) {
            current.setValue('closed_at', new GlideDateTime().getDisplayValue());
        }
    }

    // If reopening (moving from a closed state to an open state), clear the timestamp
    if ((oldState == '3' || oldState == '4' || oldState == '7') &&
        (newState == '1' || newState == '2' || newState == '-5')) {
        current.setValue('closed_at', '');
    }
})(current, previous);
